// Login Test Suite
// Generated by Qentrix

import test from '../testFixtures/fixture.js';

test.describe.parallel('Login Tests @smoke @regression', () => {

    test('[TC-560] Verify that login works with valid credentials @smoke', async ({ loginPage }) => {
        await test.step('Navigate to login page', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('Verify login page is displayed', async () => {
            await loginPage.verifyLoginPageDisplayed();
        });

        await test.step('Enter valid username and password', async () => {
            await loginPage.loginWithValidCredentials('Admin');
        });

        await test.step('Verify user is logged in successfully', async () => {
            await loginPage.verifyLoginSuccessful();
        });
    });

    test('[TC-21] Verify that login works with valid credentials - Alternative @smoke', async ({ loginPage }) => {
        await test.step('Open login page', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('Login page should display', async () => {
            await loginPage.verifyLoginPageDisplayed();
        });

        await test.step('Enter valid username - Username accepted', async () => {
            const credentials = loginPage.getLoginDataByRole('Admin');
            await loginPage.enterUsername(credentials.username);
        });

        await test.step('Enter valid password - Password accepted', async () => {
            const credentials = loginPage.getLoginDataByRole('Admin');
            await loginPage.enterPassword(credentials.password);
        });

        await test.step('Click login button - User should login successfully', async () => {
            await loginPage.clickLoginButton();
            await loginPage.verifyLoginSuccessful();
        });
    });

    test('[TC-561] Verify that login fails with invalid username @regression', async ({ loginPage }) => {
        await test.step('Navigate to login page', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('Enter invalid username and valid password', async () => {
            const credentials = loginPage.getLoginDataByRole('Admin');
            await loginPage.loginWithInvalidUsername('invaliduser@test.com', credentials.password);
        });

        await test.step('Verify authentication fails with 401 error', async () => {
            await loginPage.verifyInvalidCredentialsError();
        });
    });

    test('[TC-562] Verify that login fails with invalid password @regression', async ({ loginPage }) => {
        await test.step('Navigate to login page', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('Enter valid username and invalid password', async () => {
            const credentials = loginPage.getLoginDataByRole('Admin');
            await loginPage.loginWithInvalidPassword(credentials.username, 'WrongPassword123!');
        });

        await test.step('Verify authentication fails with 401 error', async () => {
            await loginPage.verifyInvalidCredentialsError();
        });
    });

    test('[TC-563] Verify that login fails with empty username @regression', async ({ loginPage }) => {
        await test.step('Navigate to login page', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('Submit login with empty username field', async () => {
            const credentials = loginPage.getLoginDataByRole('Admin');
            await loginPage.loginWithEmptyUsername(credentials.password);
        });

        await test.step('Verify error message indicates missing username', async () => {
            await loginPage.verifyMissingUsernameError();
        });
    });

    test('[TC-564] Verify that login fails with empty password @regression', async ({ loginPage }) => {
        await test.step('Navigate to login page', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('Submit login with empty password field', async () => {
            const credentials = loginPage.getLoginDataByRole('Admin');
            await loginPage.loginWithEmptyPassword(credentials.username);
        });

        await test.step('Verify error message indicates missing password', async () => {
            await loginPage.verifyMissingPasswordError();
        });
    });

    test('[TC-22] To Test Login Form with Invalid Data @regression', async ({ loginPage }) => {
        await test.step('Navigate to 192.168.10.124:4001', async () => {
            await loginPage.navigateToLoginPage();
        });

        await test.step('System should display Login Page with Email, Password fields, Login button and Register Hyperlink', async () => {
            await loginPage.verifyLoginPageDisplayed();
            await loginPage.verifyRegisterLinkDisplayed();
        });

        await test.step('Enter username and password - system should accept the username and password', async () => {
            await loginPage.loginWithInvalidUsername('invalid@test.com', 'invalidpass');
        });

        await test.step('Verify login fails with invalid data', async () => {
            await loginPage.verifyInvalidCredentialsError();
        });
    });

});

